/**
 * Multiplies this color and the given color
 *
 * @param color the color
 * @return this color.
 */
public Color mul(Color color) {
    this.r *= color.r;
    this.g *= color.g;
    this.b *= color.b;
    this.a *= color.a;
    return clamp();
}
